import scala.collection.mutable.{Queue, ArrayBuffer, HashMap}

def isPrime(num: Long): Boolean = {
    if (num <= 1) false
    else if (num == 2) true
    else if (num % 2 == 0) false
    else {
        val sqrtNum = math.sqrt(num).toLong
        var i = 3L
        var prime = true
        while (i <= sqrtNum && prime) {
            if (num % i == 0) prime = false
            i += 2
        }
        prime
    }
}

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 1) return 0L

    val primeToIndices = HashMap[Long, ArrayBuffer[Int]]()
    for (i <- 0 until n) {
        val num = nums(i)
        if (isPrime(num)) {
            primeToIndices.getOrElseUpdate(num, ArrayBuffer[Int]()) += i
        }
    }

    val visited = Array.fill(n)(false)
    val queue = Queue[(Int, Long)]()
    queue.enqueue((0, 0L))
    visited(0) = true

    while (queue.nonEmpty) {
        val (current, steps) = queue.dequeue()
        if (current == n - 1) return steps

        // Check adjacent moves
        for (neighbor <- Array(current - 1, current + 1)) {
            if (neighbor >= 0 && neighbor < n && !visited(neighbor)) {
                visited(neighbor) = true
                queue.enqueue((neighbor, steps + 1))
            }
        }

        // Check prime teleportation
        val num = nums(current)
        if (isPrime(num)) {
            primeToIndices.get(num).foreach { indices =>
                for (j <- indices) {
                    if (j != current && !visited(j)) {
                        visited(j) = true
                        queue.enqueue((j, steps + 1))
                    }
                }
            }
        }
    }

    -1L
}
